/**
 * Read-only **request package** summary before submit. Parents pass rows built from
 * customer context + draft lines; optional **requester context** (who submits, for which
 * company) is surfaced prominently — no `fetch` here.
 */
import type { ReactNode } from "react";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  cn,
} from "@procertus-ui/ui";

export type RequestPackageRow = {
  id: string;
  /** e.g. “Product type” */
  label: string;
  /** e.g. stream id or free text. */
  value: ReactNode;
};

/** Person submitting the package and the company the package belongs to. */
export type RequestPackageRequesterContext = {
  requesterName: string;
  requesterEmail?: string;
  organizationName: string;
  /** VAT, legal seat, workspace, etc. */
  organizationDetails?: ReactNode;
};

/** Optional copy overrides (e.g. i18n). English defaults apply when omitted. */
export type RequestPackageReviewRequesterPresentation = {
  context: RequestPackageRequesterContext;
  /** @default "Requester & organization" */
  sectionTitle?: string;
  /** @default "Submitted by" */
  requesterLabel?: string;
  /** @default "Email" */
  requesterEmailLabel?: string;
  /** @default "Organization" */
  organizationLabel?: string;
};

export type RequestPackageReviewProps = {
  className?: string;
  title: string;
  description?: string;
  /** Optional intro above the table. */
  notice?: ReactNode;
  /** Key/value rows. */
  rows: RequestPackageRow[];
  /** Renders when `rows` is empty. */
  emptyState?: ReactNode;
  /** Who is submitting and for which company — shown above `notice` / table when set. */
  requester?: RequestPackageReviewRequesterPresentation;
};

const DEFAULT_SECTION = "Requester & organization";
const DEFAULT_LABEL_REQUESTER = "Submitted by";
const DEFAULT_LABEL_EMAIL = "Email";
const DEFAULT_LABEL_ORG = "Organization";

export function RequestPackageReview({
  className,
  title,
  description,
  notice,
  rows,
  emptyState,
  requester,
}: RequestPackageReviewProps) {
  const rc = requester?.context;
  const sectionTitle = requester?.sectionTitle ?? DEFAULT_SECTION;
  const requesterLabel = requester?.requesterLabel ?? DEFAULT_LABEL_REQUESTER;
  const requesterEmailLabel = requester?.requesterEmailLabel ?? DEFAULT_LABEL_EMAIL;
  const organizationLabel = requester?.organizationLabel ?? DEFAULT_LABEL_ORG;

  return (
    <Card className={cn("w-full max-w-2xl overflow-hidden", className)}>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        {description ? <CardDescription>{description}</CardDescription> : null}
      </CardHeader>
      <CardContent className="space-y-component">
        {rc ? (
          <section
            className="rounded-lg border border-border/60 bg-muted/20 p-4 text-sm"
            aria-labelledby="request-package-requester-heading"
          >
            <h3 id="request-package-requester-heading" className="text-sm font-semibold text-foreground">
              {sectionTitle}
            </h3>
            <div className="mt-3 grid gap-4 sm:grid-cols-2">
              <div className="min-w-0 space-y-2">
                <div>
                  <p className="text-[11px] font-medium uppercase tracking-wide text-muted-foreground">
                    {requesterLabel}
                  </p>
                  <p className="mt-1 font-medium leading-snug text-foreground">{rc.requesterName}</p>
                </div>
                {rc.requesterEmail ? (
                  <div>
                    <p className="text-[11px] font-medium uppercase tracking-wide text-muted-foreground">
                      {requesterEmailLabel}
                    </p>
                    <p className="mt-1 min-w-0 break-all">
                      <a
                        href={`mailto:${rc.requesterEmail}`}
                        className="text-primary underline-offset-2 hover:underline"
                      >
                        {rc.requesterEmail}
                      </a>
                    </p>
                  </div>
                ) : null}
              </div>
              <div className="min-w-0 space-y-2">
                <div>
                  <p className="text-[11px] font-medium uppercase tracking-wide text-muted-foreground">
                    {organizationLabel}
                  </p>
                  <p className="mt-1 font-medium leading-snug text-foreground">{rc.organizationName}</p>
                </div>
                {rc.organizationDetails ? (
                  <div className="text-muted-foreground [&_p+p]:mt-2">{rc.organizationDetails}</div>
                ) : null}
              </div>
            </div>
          </section>
        ) : null}

        {notice ? <div className="text-sm text-muted-foreground">{notice}</div> : null}
        {rows.length === 0 ? (
          (emptyState ?? <p className="text-sm text-muted-foreground" role="status">Nothing to review — add at least one request.</p>)
        ) : (
          <div className="overflow-x-auto rounded-md border border-border/50">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-2/5">Item</TableHead>
                  <TableHead>Value</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {rows.map((r) => (
                  <TableRow key={r.id}>
                    <TableCell className="whitespace-nowrap text-muted-foreground align-top">
                      {r.label}
                    </TableCell>
                    <TableCell className="min-w-0 break-words align-top font-medium text-foreground">{r.value}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

